  bwilson: [
    { impact: 'positive', category: 'rhetoric', date: '2022–2024', tags: ['Consistency', 'Rhetoric vs Reality'],
      headline: 'Pattern: backs his rhetoric with action at real personal and political cost',
      facts: 'Wilson’s record shows a consistent willingness to pay to match his words: he made Great Salt Lake conservation a resourced Speakership priority, resigned the Speakership rather than campaign and govern at once, then spent roughly $2.8M of his own money on a Senate bid that finished a distant third.',
      why: 'Repeatedly accepting personal cost to follow through on a stated principle is a strong consistency signal, even when the political bet does not pay off.',
      source: { label: 'Deseret News', url: 'https://www.deseret.com/utah/2023/9/18/23879093/brad-wilson-resigning-from-utah-legislature/' } },
    { impact: 'positive', category: 'rhetoric', date: '2022–2023', tags: ['Notable Actions', 'Positive Leadership'],
      headline: 'Made the Great Salt Lake rescue his signature cause as Speaker',
      facts: 'As House Speaker, Wilson — a Kaysville construction businessman — made Great Salt Lake conservation a top priority, arguing that acting early would save Utah billions and steering investment into agricultural water optimization.',
      why: 'A sustained, resourced policy commitment that matched his public rhetoric across multiple sessions.',
      source: { label: 'Utah Public Radio', url: 'https://www.upr.org/utah-news/2022-08-08/saving-great-salt-lake-now-will-save-utah-billions-rep-brad-wilson-says' } },
    { impact: 'positive', category: 'transparency', date: '2023', tags: ['Public Behavior', 'Public Statements'],
      headline: 'Resigned the Speakership rather than campaign and govern at once',
      facts: 'Wilson resigned as Speaker and from the Legislature in November 2023 ahead of his U.S. Senate run, saying he could not fully serve his district and campaign at the same time and that Utah deserved a “full-time speaker.”',
      why: 'Taking a personal cost to avoid splitting his duties between office and a campaign is a stated-principle-matching-action signal.',
      source: { label: 'Deseret News', url: 'https://www.deseret.com/utah/2023/9/18/23879093/brad-wilson-resigning-from-utah-legislature/' } },
    { impact: 'positive', category: 'rhetoric', date: '2022', tags: ['Consistency'],
      headline: 'Tied the lake’s dust risk to Hill AFB and military readiness',
      facts: 'Wilson connected the shrinking lake’s exposed lakebed and dust to risks for Utah military operations including Hill Air Force Base, citing the Owens Lake precedent — linking an environmental cause to his Davis County district’s economic anchor.',
      why: 'Framing a priority around the institutions his constituents depend on reflects representational consistency.',
      source: { label: 'Great Salt Lake Collaborative', url: 'https://greatsaltlakenews.org/latest-news/deseret-news/can-the-great-salt-lake-and-its-dust-pollution-derail-utah-military-operations-officials-look-for-answers' } },
    { impact: 'negative', category: 'redflags', date: '2024', tags: ['Rhetoric vs Reality', 'Public Behavior'],
      headline: 'Self-funded ~$2.8M Senate bid finished a distant third',
      facts: 'Wilson invested roughly $2.8M of his own money in his 2024 U.S. Senate campaign but never gained traction, stopped buying ads by early June, and lost the GOP primary to John Curtis, trailing Trent Staggs as well.',
      why: 'How a well-resourced, high-profile bid was run and lost is part of the public-conduct read.',
      source: { label: 'The Salt Lake Tribune', url: 'https://www.sltrib.com/news/politics/2024/06/04/brad-wilsons-us-senate-campaign/' } },
    { impact: 'positive', category: 'transparency', date: '2025', tags: ['Positive Leadership'],
      headline: 'Named CEO of the Salt Lake City–Utah 2034 Winter Olympics',
      facts: 'After leaving politics, Wilson was named CEO of the Salt Lake City–Utah 2034 Olympic and Paralympic organizing effort in February 2025.',
      why: 'A continued high-trust public leadership role after an electoral loss reflects standing beyond a single campaign.',
      source: { label: 'Wikipedia', url: 'https://en.wikipedia.org/wiki/Brad_Wilson_(politician)' } },
  ],
